 51	  const [newSecret, setNewSecret] = useState<IoK8sApiCoreV1Secret>(
 52	    getSecretTemplateWithNamespace(initialProjectName),
 53	  );
 54	
 55	  if (!newSecret) {
 56	    return <span className="text-muted">{t('No credentials found.')}</span>;
 57	  }
 58	
 59	  const onNewSecretChange = (newValue: IoK8sApiCoreV1Secret) => {
 60	    setApiError(null);
 61	    setValidationError(validateProviderAndSecret(newProvider, newValue, providerNames));
 62	    setNewSecret(newValue);
 63	  };
 64	
 65	  const onNewProviderChange = (newValue: V1beta1Provider) => {
 66	    setApiError(null);
 67	    setValidationError(validateProviderAndSecret(newValue, newSecret, providerNames));
 68	    // Sync secret with new URL
 69	    const updatedSecret = {
 70	      ...newSecret,
 71	      data: { ...newSecret.data, url: encode(newValue?.spec?.url ?? '') },
 72	    };
 73	    setNewProvider(newValue);
 74	    setNewSecret(updatedSecret);
 75	  };
 76	
 77	  const onProjectNameChange = (newValue: string) => {
 78	    setApiError(null);
 79	    setProjectName(newValue);
 80	  };
 81	
 82	  const onUpdate = async () => {
 83	    toggleIsLoading();
 84	
 85	    const vsphereEndpointData = newProvider.spec?.type === 'vsphere' && {
 86	      vsphereEndpointType: getSdkEndpoint(newProvider),
 87	    };
 88	
 89	    trackEvent(TELEMETRY_EVENTS.PROVIDER_CREATE_STARTED, {
 90	      namespace: projectName,
 91	      providerType: newProvider.spec?.type,
 92	      ...vsphereEndpointData,
 93	    });
 94	
 95	    try {
 96	      const secret: IoK8sApiCoreV1Secret | undefined = await createProviderSecret(
 97	        newProvider,
 98	        produce(newSecret, (draft) => {
 99	          if (projectName) {
100	            if (draft?.metadata) draft.metadata.namespace = projectName;
101	          }
102	        }),
103	      );
104	
105	      const provider: V1beta1Provider | undefined = await createProvider(
106	        produce(newProvider, (draft) => {
107	          if (projectName) {
108	            if (draft?.metadata) draft.metadata.namespace = projectName;
109	          }
110	        }),
111	        secret!,
112	      );
113	
114	      // set secret ownership using provider uid
115	      await patchProviderSecretOwner(provider, secret);
116	
117	      trackEvent(TELEMETRY_EVENTS.PROVIDER_CREATE_COMPLETED, {
118	        hasVddk: Boolean(newSecret.data?.vddkImage),
119	        namespace: projectName,
120	        providerType: provider?.spec?.type,
121	        ...(provider?.spec?.type === 'vsphere' && {
122	          vsphereEndpointType: getSdkEndpoint(provider),
123	        }),
124	      });
125	
126	      // navigate to providers derails page
127	      const providerURL = getProviderDetailsPageUrl(provider);
128	
129	      navigate(providerURL);
130	    } catch (err) {
131	      trackEvent(TELEMETRY_EVENTS.PROVIDER_CREATE_FAILED, {
132	        error: err instanceof Error ? err.message : 'Unknown error',
133	        namespace: projectName,
134	        providerType: newProvider.spec?.type,
135	        ...vsphereEndpointData,
136	      });
137	
138	      setApiError(err as Error | null);
139	      toggleIsLoading();
140	    }
141	  };
142	
143	  return (
144	    <PageSection variant="default">
145	      <Form>
146	        <ProvidersCreatePageHeader apiError={apiError} />
147	
148	        <ProvidersCreateFormsSection
149	          newProvider={newProvider}
150	          newSecret={newSecret}
151	          projectName={projectName}
152	          onNewProviderChange={onNewProviderChange}
153	          onNewSecretChange={onNewSecretChange}
154	          onProjectNameChange={onProjectNameChange}
155	          providerNames={providerNames}
156	          providerNamesLoaded={providerNamesLoaded}
157	        />
158	
159	        <Divider className="forklift-section-create-divider" />
160	
161	        <ProviderCreateActionsSection
162	          newProvider={newProvider}
163	          projectName={projectName}
164	          activeNamespace={activeNamespace}
165	          validationError={validationError}
166	          isLoading={isLoading}
167	          onUpdate={onUpdate}
168	        />
169	      </Form>
170	    </PageSection>
171	  );
172	};
173	
174	export default ProvidersCreatePage;
